 *   constraints (using smt_bv_add_eq, each adding 128 clauses) to fill the
 *   CLBUF close to the clause cap, then add a constraint that must push the
 *   buffer over capacity.  Assert: smt_solve() returns SMT_E_TOO_BIG, never
 *   SMT_SAT or SMT_UNSAT (a SAT verdict from an incomplete buffer is false). */
var SMT_KAT8_C2  : [i64; 2]
var SMT_KAT8_V2  : [u32; 2]

fn smt_kat8a() -> u64 {
    /* Part A: overflow in smt_check_lia_one must fail-closed. */
    smt_init()
    let x : u32 = smt_lia_new_var()
    let y : u32 = smt_lia_new_var()
    if x != 1u32 { return 1u64 }
    if y != 2u32 { return 2u64 }
    /* x == 1 (equality) */
    SMT_KAT8_C2[0u64] = 1i64
    SMT_KAT8_V2[0u64] = 1u32
    let cp : *i64 = (&SMT_KAT8_C2 as u64) as *i64
    let vp : *u32 = (&SMT_KAT8_V2 as u64) as *u32
    if smt_lia_add_eq(cp, vp, 1u32, 1i64) != SMT_OK { return 3u64 }
    /* Construct a second constraint with coefficient 2^62 on x plus 2^62 on y,
     * bound 0.  The constraint is (2^62)*x + (2^62)*y == 0.  With x=1, y=0
     * (a valid LIA relaxation model), the check sum = 2^62 + 0 = 2^62, which
     * does NOT equal 0, so the constraint is violated.  But with raw `*` and
     * `+`, a second call 2^62*1 + 2^62*0 does not overflow on its own.
     * Instead test the ADD overflow: set both coeffs to 2^62; with a model
     * that sets x=1, y=1 (if feasible), sum = 2^62 + 2^62 wraps raw.
     * Force both vars to 1 via: x <= 1, x >= 1, y <= 1, y >= 1. */
    /* x >= 1 (stored as -x <= -1) */
    SMT_KAT8_C2[0u64] = 1i64
    SMT_KAT8_V2[0u64] = 1u32
    if smt_lia_add_ge(cp, vp, 1u32, 1i64) != SMT_OK { return 4u64 }
    /* y == 1 */
    SMT_KAT8_C2[0u64] = 1i64
    SMT_KAT8_V2[0u64] = 2u32
    if smt_lia_add_eq(cp, vp, 1u32, 1i64) != SMT_OK { return 5u64 }
    /* Overflow constraint: 2^62 * x + 2^62 * y == 0 (violated by x=y=1,
     * sum=2^63 wraps to 0 raw -> false SAT; fixed: SMT_OVF set -> E_NOMODEL) */
    let big : i64 = 0x4000000000000000i64
    SMT_KAT8_C2[0u64] = big
    SMT_KAT8_C2[1u64] = big
    SMT_KAT8_V2[0u64] = 1u32
    SMT_KAT8_V2[1u64] = 2u32
