fn smt_kat8b() -> u64 {
    /* Part B: clause-buffer overflow must never produce SAT.
     * smt_bv_add_eq on width-w adds 2*w clauses.  SMT_CLBUF_MAX_CLS = 262144.
     * Use width 64: 128 clauses per eq call.  262144 / 128 = 2048 exact.
     * We can only have SMT_MAX_BV_VARS=256 vars; each pair needs 2 vars.
     * So we can add at most 128 pairs before running out of BV vars.
     * 128 pairs * 128 clauses = 16384 clauses -- not enough to overflow CLS cap.
     * The bit-lits cap is SMT_CLBUF_MAX_LITS=1048576.  Each eq on w=64 adds
     * 128 clauses * 2 lits = 256 lits.  1048576 / 256 = 4096 per eq pair.
     * Use smt_bv_add_neq for the XOR part: smt_bv_xor_bit adds 4*w clauses *
     * 3 lits = 12*w lits per var pair.  w=1 for compact fill.
     * Simplest: use smt_bv_add_ult on width-64, which adds ~9 clauses per bit
     * = ~576 clauses per call.  262144 / 576 ~ 455 calls, but we only have
     * 256 vars.  Use small width=4: smt_bv_add_ult adds 9*4=36 clauses per
     * call.  262144 / 36 ~ 7281 calls, still var-limited.
     * Direct approach: call smt_bv_add_eq repeatedly on same pair (same vars,
     * duplicate clauses are fine for buffer fill).  smt_bv_add_eq on width 64
     * adds 128 clauses.  To fill to within 1 of cap: 262143 / 128 = 2048 full
     * calls use 262144 lits of clause-index but we hit CLS cap first.
     * The SMT_CLBUF_ERR latch fires when NCL >= MAX_CLS, not just LITS.
     * Plan: add 2047 * smt_bv_add_eq (width-64) = 2047*128=262016 clauses,
     * then add one more eq (128 more clauses would make 262144 = MAX_CLS),
     * the FIRST clause of that eq triggers the CLS cap -> CLBUF_ERR=1.
     * After that smt_solve must return SMT_E_TOO_BIG, not SAT/UNSAT. */
    smt_init()
    /* two 64-bit vars */
    let a : u32 = smt_bv_new_var(64u32)
    let b : u32 = smt_bv_new_var(64u32)
    if a != 1u32 { return 1u64 }
    if b != 2u32 { return 2u64 }
    /* fill: each call adds 128 clauses; 262144/128 = 2048 calls exactly saturate
     * the cap; the 2048th call's FIRST sub-call to smt_clbuf_add2 will see
     * NCL==262144-1 for the last slot, actually NCL hits MAX_CLS on slot 262144.
     * Let's add 2047 full calls (2047*128=262016 clauses), then one more.
     * That one more starts at NCL=262016; each smt_clbuf_add2 increments NCL
     * by 1; the 129th sub-add of the 2048th call hits NCL=262144=MAX_CLS. */
    let mut k : u32 = 0u32
    while k < 2047u32 {
        smt_bv_add_eq(a, b)
        k = k + 1u32
    }
    /* One more eq: this will overflow CLBUF_NCL to >= MAX_CLS during the
     * internal smt_clbuf_add2 calls, setting CLBUF_ERR = 1. */
    smt_bv_add_eq(a, b)
    /* SMT_CLBUF_ERR must be set by now */
    if SMT_CLBUF_ERR == 0u8 { return 3u64 }
    /* smt_solve must NOT return SAT (that would be unsound: buffer is incomplete) */
    let r : i32 = smt_solve()
    if r == SMT_SAT { return 4u64 }
    /* must return E_TOO_BIG, not UNSAT (UNSAT from an incomplete buffer is also unsound) */
    if r != SMT_E_TOO_BIG { return 5u64 }
    return 0u64
}

