extern @abi(c-msvc-x64) fn smt_solve() -> i32 from "smt.iii"

const SMT_SAT      : i32 = 1i32
const SMT_E_TOO_BIG: i32 = -1i32
const SMT_OK       : i32 = 0i32

var COEF : [i64; 2]
var VARS : [u32; 2]

fn case_a() -> u64 {
    smt_init()
    let x : u32 = smt_lia_new_var()
    let y : u32 = smt_lia_new_var()
    let cp : *i64 = (&COEF as u64) as *i64
    let vp : *u32 = (&VARS as u64) as *u32
    COEF[0u64] = 1i64  VARS[0u64] = x
    if smt_lia_add_eq(cp, vp, 1u32, 1i64) != SMT_OK { return 1u64 }
    if smt_lia_add_ge(cp, vp, 1u32, 1i64) != SMT_OK { return 2u64 }
    COEF[0u64] = 1i64  VARS[0u64] = y
