    VARS[0u64] = x    VARS[1u64] = y
    if smt_lia_add_eq(cp, vp, 2u32, 0i64) != SMT_OK { return 4u64 }
    /* Must NOT return SAT -- the constraint is unsatisfied */
    if smt_solve() == SMT_SAT { return 5u64 }
    return 0u64
}

fn case_b() -> u64 {
    smt_init()
    let a : u32 = smt_bv_new_var(64u32)
    let b : u32 = smt_bv_new_var(64u32)
