    if smt_solve() == SMT_SAT { return 3u64 }
    /* must return E_TOO_BIG */
    if smt_solve() != SMT_E_TOO_BIG { return 4u64 }
    return 0u64
}

fn main() -> u64 {
    let ra : u64 = case_a()
    if ra != 0u64 { return ra }
    let rb : u64 = case_b()
    if rb != 0u64 { return 10u64 + rb }
    return 99u64
}
